mcqs.question:
What is the output?
int arr[3] = {10, 20, 30};
int *p = arr + 1;
printf("%d", *p);

What is the output?
int a[5] = {1,2,3,4,5};
int *p = a;
int *q = &a[4];
printf("%d", q - p);

What is the output?
int arr[3] = {10, 20, 30};
printf("%d %d", *arr, *(arr+1));

What is the output?
int x = 10;
int *p = &x;
printf("%d", *&*&x);
